                "parentName": "什邡瑞邦机械有限责任公司党委"
              }
            ],
            "name": "什邡瑞邦机械有限责任公司党委",
            "sort": 2,
            "createDate": "2025-12-18 10:22:34",
            "parentName": "中共中国铁路成都局集团有限公司委员会"
          }
        ],
        "name": "中共中国铁路成都局集团有限公司委员会",
        "sort": 1,
        "createDate": "2025-12-18 10:22:28",
        "parentName": null
      }
    ]
  }
  if (props.firstLevel) {
    const d = [
      {
        ...props.firstLevel,
        children: res.data.list,
      },
    ];
    deptList.value = d;
  } else if (props.isFilterSelf) {
    deptList.value = filterDeptTree(res.data);
  } else {
    deptList.value = res.data;
  }
  map(res.data);

}

function handleChange(data) {
  emit('update:modelValue', data);
  emit('update:deptName', depNameMap[data]);
}

/**
 * 过滤掉指定ID的部门节点
 * @param {Array} deptTree - 部门树形结构数据
 * @param {String} realDeptId - 需要排除的部门ID
 * @returns {Array} 过滤后的部门树形结构
 */
const filterDeptTree = (deptTree) => {
  const id = props?.userDeptId;
  if (!deptTree || !Array.isArray(deptTree)) {
    return [];
  }

  return deptTree.filter((node) => {
    // 如果当前节点是要排除的节点，直接过滤掉
    if (node.id === id) {
      return false;
    }
    // 如果有子节点，递归过滤子节点
    if (node.children && node.children.length > 0) {
      node.children = filterDeptTree(node.children);
    }

    return true;
  });
};
// 使用watch userDeptId 过滤掉指定ID的部门节点
watchEffect(() => {
  if (props.userDeptId) {
    getDeptList(); // 重新获取并过滤数据
  }
});
</script>
